{"content":"import { type FormEvent, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import Button from '../../components/ui/Button.tsx'
import Input from '../../components/ui/Input.tsx'
import { useAuth } from '../../hooks/useAuth.tsx'

export default function LoginPage() {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const { signInWithEmail } = useAuth()
  const navigate = useNavigate()

  async function handleSubmit(e: FormEvent<HTMLFormElement>) {
    e.preventDefault()
    setError(null)
    setLoading(true)

    const result = await signInWithEmail(email, password)

    if (result.error) {
      setError(result.error)
      setLoading(false)
    } else {
      navigate('/app')
    }
  }

  return (
    <form
      onSubmit={handleSubmit}
      className="space-y-6 rounded-xl bg-white p-8 shadow-sm"
    >
      <h2 className="text-center text-xl font-semibold text-gray-900">
        Se connecter
      </h2>

      {error && (
        <p className="rounded-lg bg-red-50 p-3 text-center text-sm text-red-600">
          {error}
        </p>
      )}

      <Input
        label="Email"
        type="email"
        placeholder="vous@exemple.com"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        required
      />

      <Input
        label="Mot de passe"
        type="password"
        placeholder="••••••••"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        required
      />

      <Button type="submit" className="w-full" disabled={loading}>
        {loading ? 'Connexion...' : 'Se connecter'}
      </Button>

      <div className="flex flex-col items-center gap-2 text-sm">
        <Link to="/forgot-password" className="text-blue-600 hover:underline">
          Mot de passe oublié ?
        </Link>
        <Link to="/register" className="text-blue-600 hover:underline">
          Créer un compte
        </Link>
      </div>
    </form>
  )
}
"}

{"content":"import { useState, useMemo } from 'react'
import type { DateRange } from '../types/analytics'
import {
  analyticsOverview,
  monthlyTrends,
  dailyMetrics,
  modelMetrics,
  trackedQueries,
  recentCitations,
  aiModels,
} from '../data/mockAnalytics'

export function useAnalytics() {
  const [dateRange, setDateRange] = useState<DateRange>('30d')
  const [isLoading] = useState(false)

  const filteredDailyMetrics = useMemo(() => {
    const days = dateRange === '7d' ? 7 : dateRange === '30d' ? 30 : 30
    return dailyMetrics.slice(-days)
  }, [dateRange])

  const filteredMonthlyTrends = useMemo(() => {
    const months =
      dateRange === '7d' ? 1
      : dateRange === '30d' ? 3
      : dateRange === '90d' ? 6
      : dateRange === '6m' ? 6
      : 12
    return monthlyTrends.slice(-months)
  }, [dateRange])

  return {
    dateRange,
    setDateRange,
    isLoading,
    overview: analyticsOverview,
    dailyMetrics: filteredDailyMetrics,
    monthlyTrends: filteredMonthlyTrends,
    modelMetrics,
    trackedQueries,
    recentCitations,
    aiModels,
  }
}
"}

